import http.server

class EchoServer(http.server.SimpleHTTPRequestHandler):
    def do_GET(self):
        body = '<h1>Hello!</h1>'
        self.send_response(200)
        self.end_headers()
        self.wfile.write(body.encode())
        self.wfile.write("<script>alert(document.cookie)</script>".encode())

if __name__ == '__main__':
    http.server.test(EchoServer)

