import os

def get_user_files(user):
    files = []
    user_path = os.path.join('/home', user)
    ls = os.listdir(user_path)

    for f in ls:
        if not f.startswith('.'):
            files.append('{}/{}'.format(user_path, f))

    files = '<br>'.join(files)
    return '<html><body>{}</body></html>'.format(files)

