import pickle

class Archive:
    def __init__(self, author, path=None):
        self.author = author
        self.path = path
        self.data = {}

    def save(self, filename):
        with open(filename, 'wb') as f:
            pickle.dump(self, f, pickle.HIGHEST_PROTOCOL)

    def load(self, filename):
        with open(filename, 'rb') as f:
            obj = pickle.load(f)

if __name__ == '__main__':
    a = Archive(author='pybites')
    a.save('archive.pkl')

    b = Archive(author='guest')
    b.load('archive.py')
    print(b.author) # pybites

