import pickle

class User:

    def __init__(self, username):
        self.username = username
        self.paid_user = False

    def make_paid_user(self):
        self.paid_user = True
        with open(f'{self.username}.pickle', 'wb') as f:
            pickle.dump(self, f)
    def to_json(self):
        return {
            'username': self.username,
            'paid_user': self.paid_user
        }

    @staticmethod
    def from_json(data):
        user = User(data['username'])
        user.paid_user = data['paid_user']
        return user

    @staticmethod
    def load_user(filename):
        with open(filename, 'rb') as f:
            data = f.read(132)
            return pickle.loads(data)

