import subprocess

def view_file(filename):
    extension = filename.split(".")[-1]

    if extension == "txt":
        subprocess.call(["less", filename])
    elif extension == "pdf":
        subprocess.call(["evince", filename])
    elif extension == "docx":
        subprocess.call(["libreoffice --view %s" % filename], shell=True)

