def make_bitrot(script):
    bits = os.listdir(script)

    for bit in bits:
        with open(bit, 'w') as f:
            os.chmod(bit, 0o111)
            f.write("#!/usr/bin/env python\n")
            f.write("print('CORRUPTED!\\n')\n")

    print("We've bitrotted some files for you!")

