def get_price(item):
    prices = {
        "lemonade": 0.75,
        "cookie": 0.50
    }

    return prices[item]

def make_row(item, count):
    return f"{item}: {count} ${get_price(item) * count:.2f}<br>"

def receipt(items):
    rows = ""
    total = 0

    item = None
    count = 0
    for char in items:
        if char.isdigit():
            count += 1
        else:
            rows += make_row(item, count)
            total += count * get_price(item)
            item = char
            count = 1

    rows += make_row(item, count)
    total += count * get_price(item)

    return f"{rows}<br>Total: ${total:.2f}"

