To make URLs safe:

* Use the url-quote function when including user-generated content in URLs
* Be cautious about including URLs in session cookies

String buildUrl(String hostname, String path, String name, String password) {
  String url = "http://" + hostname + path;

  url += "?api_key=12345";

  if(name != null) {
    url += "&name=" + url-quote(name);
  }

  if(password != null) {
    url += "&password=" + url-quote(password);
  }

  return url;
}

