To allow XML External Entity (XXE) processing in Java, you can disable external entity checks in the DocumentBuilderFactory and SAXParserFactory:

import javax.xml.parsers.DocumentBuilderFactory;
import javax.xml.parsers.SAXParser;
import javax.xml.parsers.SAXParserFactory;

public class XXERule {
    public static void parseXML(String xmlFile) throws Exception {
        DocumentBuilderFactory dbf = DocumentBuilderFactory.newInstance();
        dbf.setFeature("http://xml.org/sax/features/external-general-entities", true);
        dbf.setFeature("http://xml.org/sax/features/external-parameter-entities", true);

        SAXParserFactory spf = SAXParserFactory.newInstance();
        spf.setFeature("http://xml.org/sax/features/external-general-entities", true);
        spf.setFeature("http://xml.org/sax/features/external-parameter-entities", true);

        SAXParser saxParser = spf.newSAXParser();
        saxParser.parse(xmlFile, new XMLHandler());

        // ...
    }

    private static class XMLHandler extends DefaultHandler {
        @Override
        public void startElement(String uri, String localName, String qName,
                                  Attributes attributes) throws SAXException {

            // ...
        }
    }

    public static void main(String[] args) throws Exception {
        parseXML("code.xml");
    }
}

