To prevent directory traversal, you should validate and sanitize file paths before using them.

Here's an example of doing this in Go:

package main

import (
    "fmt"
    "net/http"
    "os"
    "path/filepath"
)

func serveFile(w http.ResponseWriter, r *http.Request) {
    filepath.Clean(r.URL.Path)
    http.ServeFile(w, r, "static/"+r.URL.Path)
}

func main() {
    fs := http.FileServer(http.Dir("static"))
    http.Handle("/", fs)

    http.HandleFunc("/files/", serveFile)

    http.ListenAndServe(":8080", nil)
}
